#!/usr/bin/env python3
# MBU Simulation Result Plots
# Generated by MBU_simulate.cc
# Run on host: python3 plot_results.py

import os, sys
import pandas as pd
import matplotlib.pyplot as plt
import matplotlib.ticker as mticker
import numpy as np

OUTDIR = os.path.dirname(os.path.abspath(__file__))

# --- Plot 1: Accuracy vs Bits ---
acc_path = os.path.join(OUTDIR, 'accuracy_summary.csv')
if os.path.exists(acc_path):
    df_acc = pd.read_csv(acc_path)
    fig, ax = plt.subplots(figsize=(8, 5))
    ax.bar(df_acc['bits'].astype(str), df_acc['accuracy_pct'],
           color='steelblue', edgecolor='black', width=0.5)
    ax.set_xlabel('Number of Flipped Bits (k)', fontsize=12)
    ax.set_ylabel('Accuracy (% runs matching golden)', fontsize=12)
    ax.set_title('MBU Fault Injection: Accuracy vs Bit Count', fontsize=13)
    ax.set_ylim(0, 105)
    ax.yaxis.set_major_formatter(mticker.PercentFormatter())
    for i, row in df_acc.iterrows():
        ax.text(i, row['accuracy_pct']+1.5,
                f"{row['accuracy_pct']:.1f}%",
                ha='center', fontsize=9)
    plt.tight_layout()
    plt.savefig(os.path.join(OUTDIR, 'plot_accuracy_vs_bits.png'), dpi=150)
    plt.close()
    print('[Plot] Saved: plot_accuracy_vs_bits.png')
else:
    print('[Warn] Not found:', acc_path)

bit_counts = [1,5,10,15,20]

# --- Plot 2: Prob Drop per Image (one plot per bit count) ---
for k in bit_counts:
    csv_path = os.path.join(OUTDIR, f'results_k{k}_bits.csv')
    if not os.path.exists(csv_path):
        print('[Warn] Not found:', csv_path)
        continue
    df = pd.read_csv(csv_path)
    df_valid = df[(df['timeout']==0) & (df['crash']==0)].copy()
    if df_valid.empty:
        print(f'[Warn] No valid runs for k={k}')
        continue
    avg_drop = df_valid.groupby('image_name')['prob_drop'].mean().reset_index()
    avg_drop = avg_drop.sort_values('image_name')
    short_names = [os.path.splitext(n)[0][-20:] for n in avg_drop['image_name']]
    fig, ax = plt.subplots(figsize=(max(8, len(short_names)*0.8), 5))
    colors = ['tomato' if v > 0.05 else 'steelblue' for v in avg_drop['prob_drop']]
    ax.bar(short_names, avg_drop['prob_drop'], color=colors, edgecolor='black')
    ax.axhline(0, color='black', linewidth=0.8, linestyle='--')
    ax.set_xlabel('Image', fontsize=11)
    ax.set_ylabel('Avg Prob Drop (golden - faulty)', fontsize=10)
    ax.set_title(f'MBU k={k} bits: Probability Drop per Image', fontsize=12)
    plt.xticks(rotation=45, ha='right', fontsize=8)
    plt.tight_layout()
    out_path = os.path.join(OUTDIR, f'plot_prob_drop_k{k}.png')
    plt.savefig(out_path, dpi=150)
    plt.close()
    print(f'[Plot] Saved: plot_prob_drop_k{k}.png')

print('\n[Done] All plots saved to:', OUTDIR)
for fn in sorted(os.listdir(OUTDIR)):
    if fn.endswith('.png'):
        print('  ', fn)
